import os

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
HOT_TOPICS_PATH = os.path.join(BASE_DIR, "hot_topics.json")

def load_existing():
    with open(HOT_TOPICS_PATH, "r", encoding="utf-8") as f:
        return json.load(f)

def gen_id(existing_ids, idx):
    while True:
        new_id = f"ht_202604061307_{idx:03d}"
        if new_id not in existing_ids:
            return new_id
        idx += 1

def make_topic(idx, title, hot_value, platform, industries, trends, cat_type, sentiment, keywords, brands, category, trend_tags, logic, trend_status, url=None):
    now = "2026-04-06T13:07:00"
    heat_str = f"{hot_value / 100000000:.1f}亿" if hot_value >= 100000000 else f"{hot_value / 10000:.0f}万"
    if not url:
        url_map = {
            "微博": "https://weibo.com",
            "抖音": "https://douyin.com",
            "小红书": "https://xiaohongshu.com",
            "B站": "https://bilibili.com",
            "知乎": "https://zhihu.com",
        }
        first_p = platform.split("/")[0].strip()
        url = url_map.get(first_p, "https://weibo.com")
    return {
        "id": f"ht_202604061307_{idx:03d}",
        "title": title,
        "hot_value": hot_value,
        "platform": platform,
        "industries": industries,
        "trends": trends,
        "type": cat_type,
        "sentiment": sentiment,
        "keywords": keywords,
        "c": brands,
        "created_at": now,
        "rank": 0,
        "category": category,
        "trend_tags": trend_tags,
        "url": url,
        "updated_at": now,
        "heat": heat_str,
        "logic": logic,
        "trend": trend_status,
        "isNew": True,
    }

