def main():
    existing = load_existing()
    existing_ids = {item["id"] for item in existing}
    
    # Build all new topics
    all_new_raw = tech + entertainment + sports + auto + health + beauty + food + society + travel + education + workplace + fashion + pet + home + finance + emotion + gaming + environment
    
    idx = 1
    new_topics = []
    for t in all_new_raw:
        topic = make_topic(idx, *t)
        if topic["id"] not in existing_ids:
            new_topics.append(topic)
            idx += 1
    
    # Merge
    merged = existing + new_topics
    
    # Re-rank by hot_value descending
    merged.sort(key=lambda x: x.get("hot_value", 0), reverse=True)
    for i, item in enumerate(merged):
        item["rank"] = i + 1
    
    # Save
    with open(HOT_TOPICS_PATH, "w", encoding="utf-8") as f:
        json.dump(merged, f, ensure_ascii=False, indent=2)
    
    # Validation
    total = len(merged)
    original = len(existing)
    added = total - original
    
    # Check required fields
    required_fields = ["id", "title", "hot_value", "platform", "category", "keywords", "trend", "logic"]
    issues = []
    for item in merged:
        for field in required_fields:
            if field not in item or not item[field]:
                issues.append(f"Missing {field} in {item.get('id', 'unknown')}")
    
    print(f"=== 热点数据扩展完成 ===")
    print(f"原始数据: {original} 条")
    print(f"新增数据: {added} 条")
    print(f"总计: {total} 条")
    print(f"数据完整性问题: {len(issues)} 个")
    if issues:
        for issue in issues[:10]:
            print(f"  - {issue}")
    
    # Category distribution
    from collections import Counter
    cats = Counter(item.get("category", "未知") for item in merged)
    print(f"\n分类分布:")
    for cat, count in cats.most_common():
        print(f"  {cat}: {count}条")

if __name__ == "__main__":
    main()
